import{_ as e}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{c as s,o as i,X as l}from"./chunks/vendor-vueuse.XPft87tp.js";const u=JSON.parse('{"title":"eval 的功能和危害","description":"","frontmatter":{},"headers":[],"relativePath":"basics/eval-risks.md","filePath":"basics/eval-risks.md","lastUpdated":1784884957000}'),t={name:"basics/eval-risks.md"};function n(o,a,r,d,h,p){return i(),s("div",null,a[0]||(a[0]=[l(`<h1 id="eval-的功能和危害" tabindex="-1">eval 的功能和危害 <a class="header-anchor" href="#eval-的功能和危害" aria-label="Permalink to &quot;eval 的功能和危害&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p><code>eval</code> 能把字符串当代码执行，听起来很酷——但也仅限于&quot;听起来&quot;。大多数场景下用它都是个坏主意，性能和安全两样都占不了便宜。</p><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><h3 id="eval-干了什么" tabindex="-1">eval 干了什么 <a class="header-anchor" href="#eval-干了什么" aria-label="Permalink to &quot;eval 干了什么&quot;">​</a></h3><div class="language-js vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes dracula vitesse-black vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#50FA7B;--shiki-dark:#80A665;">eval</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#444444;">(</span><span style="--shiki-light:#E9F284;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#F1FA8C;--shiki-dark:#C98A7D;">console.log(1 + 1)</span><span style="--shiki-light:#E9F284;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#444444;">)</span><span style="--shiki-light:#6272A4;--shiki-dark:#758575DD;"> // 2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>把字符串传给 JavaScript 引擎重新解析、编译、执行。正常的代码在加载时就编译好了，但 <code>eval</code> 的字符串要到运行时才能被解析，引擎做不了任何预优化。</p><h3 id="明确的风险" tabindex="-1">明确的风险 <a class="header-anchor" href="#明确的风险" aria-label="Permalink to &quot;明确的风险&quot;">​</a></h3><p><strong>性能</strong>：<code>eval</code> 阻止引擎的 JIT 优化。V8 看到 <code>eval</code> 会直接放弃对当前函数的很多优化机会——引擎不敢假设 <code>eval</code> 里面的字符串会干什么，万一它动态声明了变量、改了作用域呢？</p><p><strong>安全</strong>：</p><div class="language-js vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes dracula vitesse-black vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#FF79C6;--shiki-dark:#CB7676;">const</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#BD976A;"> userInput</span><span style="--shiki-light:#FF79C6;--shiki-dark:#444444;"> =</span><span style="--shiki-light:#E9F284;--shiki-dark:#C98A7D77;"> &#39;</span><span style="--shiki-light:#F1FA8C;--shiki-dark:#C98A7D;">alert(&quot;恶意代码&quot;)</span><span style="--shiki-light:#E9F284;--shiki-dark:#C98A7D77;">&#39;</span></span>
<span class="line"><span style="--shiki-light:#50FA7B;--shiki-dark:#80A665;">eval</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#444444;">(</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#BD976A;">userInput</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#444444;">)</span><span style="--shiki-light:#6272A4;--shiki-dark:#758575DD;"> // 相当于你亲手执行了用户输入的内容</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这本质上是个 XSS 注入的后门。用户输入的内容必须永远当作文本处理，绝不能当代码执行。</p><p><strong>调试体验</strong>：<code>eval</code> 里的代码没有行号、没有文件名，报错了你根本不知道具体是哪个 <code>eval</code> 出的问题。</p><h3 id="有没有替代方案" tabindex="-1">有没有替代方案 <a class="header-anchor" href="#有没有替代方案" aria-label="Permalink to &quot;有没有替代方案&quot;">​</a></h3><ul><li>解析 JSON：用 <code>JSON.parse</code>，不要用 <code>eval(&#39;(&#39; + json + &#39;)&#39;)</code></li><li>动态访问属性：用 <code>obj[key]</code>，不要 <code>eval(&#39;obj.&#39; + key)</code></li><li>动态计算：能不动态就不动态，实在不行用 <code>new Function()</code>——它运行在全局作用域，至少不会污染当前作用域</li></ul><h2 id="实战场景" tabindex="-1">实战场景 <a class="header-anchor" href="#实战场景" aria-label="Permalink to &quot;实战场景&quot;">​</a></h2><p>真实项目里基本不会主动用 <code>eval</code>。但有些老旧代码和第三方库里可能还藏着它。ESLint 里 <code>no-eval</code> 规则默认就是 error 级别。如果你确实需要动态执行代码（比如模板引擎），用 <code>new Function</code> 也比 <code>eval</code> 安全一点——至少它隔离了作用域。</p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p><code>eval</code> 的核心问题是把编译时机从加载推迟到了运行时，导致性能下降且无法预判副作用。能用别的方法就别碰它，这算得上 JavaScript 的最佳实践之一了。</p>`,19)]))}const v=e(t,[["render",n]]);export{u as __pageData,v as default};
